import json
with open(r"D:\桌面\毕设\exam-platform\data\all_comp_q.json", "r", encoding="utf-8") as f:
    qs = json.load(f)

# 2019
qs.append({"y":2019,"c":"设线性表L=(a1,a2,a3,...,an-2,an-1,an)采用带头结点的单链表保存，链表中的结点定义如下：typedef struct node{int data;struct node*next;}NODE;请设计一个空间复杂度为O(1)且时间上尽可能高效的算法，重新排列L中的各结点，得到线性表L=(a1,an,a2,an-1,a3,an-2,...)。要求：（1）给出算法的基本设计思想。（2）根据设计思想采用C或C++语言描述算法。（3）说明算法的时间复杂度。","a":"（1）设计思想：1.用快慢指针找到链表中间结点，将后半段逆置；2.然后将前半段和逆置后的后半段交替合并。（2）三步法略。（3）找中点O(n)，逆置O(n)，合并O(n)。总时间复杂度O(n)，空间复杂度O(1)。","ch":101,"s":10})
qs.append({"y":2019,"c":"请设计一个队列，要求满足：（1）初始时队列为空；（2）入队时允许增加队列占用空间；（3）出队后出队元素所占用的空间可重复使用，即整个队列所占用的空间只增不减；（4）入队操作和出队操作的时间复杂度始终保持O(1)。请回答：（1）该队列应选择链式存储结构还是顺序存储结构？（2）画出队列的初态和队列满时的状态示意图。（3）完成入队和出队操作的C语言实现。","a":"（1）应选择链式存储结构。链式存储可动态申请和释放结点，满足只增不减的要求(用空闲链表管理释放的结点)。顺序存储(循环队列)扩容需整体搬移，不满足O(1)。（2）初态：front=rear=空。满态：所有已申请结点均在使用中，空闲链表为空。（3）入队：若有空闲结点则复用，否则malloc新结点；加入队尾rear。出队：取front结点，将其加入空闲链表。","ch":102,"s":10})
qs.append({"y":2019,"c":"某指令格式如下：OP(4位) Ra(4位) Rb(4位) Rd(4位) OFF(16位)。（1）该计算机最多可设置多少个通用寄存器？（2）LOAD指令的机器码为8B00FF00H(十六进制)，写出该指令的汇编格式。（3）若主存容量为4GB，则PC和MAR至少各为多少位？","a":"（1）Ra、Rb、Rd各占4位，最多16个通用寄存器。（2）8B00FF00H=1000 1011 0000 0000 1111 1111 0000 0000。OP=1000(8H)，Ra=1011(11)，Rb=0000(0)，Rd=0000(0)，OFF=FF00H=-256(补码偏移)。LOAD R11,-256(R0)到R0(根据指令定义格式确定)。（3）主存4GB=2^32B，PC>=32位，MAR>=32位。","ch":204,"s":20})
qs.append({"y":2019,"c":"某计算机采用虚拟存储器，虚拟地址为32位，物理地址为28位，按字节编址，页大小为4KB。（1）虚拟地址可表示多少个页面？（2）每个进程的页表最多有多少个页表项？（3）页表项中页框号字段占多少位？","a":"（1）页大小4KB=2^12B，虚拟地址32位，虚页号=32-12=20位。最多2^20=1M个页面。（2）最多2^20=1048576个页表项。（3）物理地址28位，页内偏移12位，页框号=28-12=16位。页表项中页框号字段至少16位。","ch":303,"s":30})
qs.append({"y":2019,"c":"有n个哲学家围坐在一张圆桌边，每位哲学家面前有一根筷子。哲学家要进行思考或进餐。进餐时需要同时获得左右两根筷子。请用信号量机制解决哲学家进餐问题，要求：（1）说明所需信号量及其初值。（2）写出每位哲学家的活动过程。（3）你的解决方案能否避免死锁？说明理由。","a":"（1）信号量：chopstick[5]={1,1,1,1,1}(每根筷子互斥)；mutex=1(限制同时进餐人数)。（2）哲学家i：while(1){think();P(mutex);P(chopstick[i]);P(chopstick[(i+1)%5]);V(mutex);eat();V(chopstick[i]);V(chopstick[(i+1)%5]);}另一种方法：最多允许4位哲学家同时拿筷子(用信号量limit=4)。（3）通过限制最多4人同时拿筷子或使用mutex限制取筷子过程，可避免死锁。死锁条件：每人拿左筷子后等待右筷子形成环等待。限制人数打破环等待条件。","ch":302,"s":30})
qs.append({"y":2019,"c":"某文件系统采用索引结点表示文件，索引结点包含8个直接索引、1个一级间接索引、1个二级间接索引。磁盘块大小为1KB，块号占4B。（1）该文件系统支持的最大文件长度是多少？（2）某文件通过该文件系统存储，若要读取文件第1000B和第10,000,000B的内容，分别需要访问磁盘多少次(假设索引结点已在内存)？","a":"（1）直接：8*1KB=8KB。一级：1KB/4B=256块号到256KB。二级：256^2*1KB=64MB。总计=64MB+256KB+8KB约等于64.3MB。（2）偏移1000B=0.98KB<8KB到直接索引范围，1次磁盘访问。偏移10MB约等于10240KB>8KB+256KB=264KB，在二级索引范围。需读二级间接块(1次)到一级间接块(1次)到数据块(1次)=3次访问。","ch":304,"s":30})
qs.append({"y":2019,"c":"某局域网采用CSMA/CD协议，数据传输速率为100Mbps，主机甲和乙之间的距离为1km，信号传播速率为200000km/s。（1）该局域网的最短帧长是多少？（2）若主机甲向主机乙发送一个长度为1518字节的数据帧，主机乙在接收过程中发现该帧有差错，则主机乙如何处理？（3）主机甲在发送数据帧的过程中发生了碰撞，则主机甲在检测到碰撞后要进行什么处理？","a":"（1）争用期=2*传播时延=2*1km/200000km/s=10us。最短帧长=100Mbps*10us=1000bit=125字节。实际以太网最短帧64字节(512bit)，对应争用期5.12us。（2）发现差错(CRC校验失败)，主机乙丢弃该帧，不发送NAK。以太网不提供确认机制，由上层协议(如TCP)负责重传。（3）检测到碰撞后，主机甲立即停止发送，发送32bit的Jam(强化碰撞)信号。然后按截断二进制指数退避算法等待随机时间后重传。","ch":403,"s":40})

# 2020
qs.append({"y":2020,"c":"定义三元组(a,b,c)(a、b、c均为正数)的距离D=|a-b|+|b-c|+|c-a|。给定3个非空整数集合S1、S2和S3，分别存储在3个数组中。请设计一个尽可能高效的算法，计算并输出所有可能的三元组(a,b,c)(a属于S1,b属于S2,c属于S3)中的最小距离。（1）给出算法的基本设计思想。（2）根据设计思想描述算法。（3）说明算法的时间复杂度。","a":"（1）D=|a-b|+|b-c|+|c-a|=2*(max(a,b,c)-min(a,b,c))。最小化D等价于让三个数尽可能接近。先将三个数组分别升序排序。用三个下标i、j、k指向三个数组，每次计算当前D，然后将最小元素对应的下标后移，直到某个数组遍历完。（2）三指针法略。（3）排序O(nlogn)(n=max长度)，三指针扫描O(n)。总时间复杂度O(nlogn)。","ch":101,"s":10})
qs.append({"y":2020,"c":"若任一字符的编码都不是其他字符编码的前缀，则称这种编码具有前缀特性。现有某字符集(字符个数>=2)的不等长编码，每个字符的编码均为二进制的0、1序列，最长为L位。（1）哪种数据结构适宜保存上述字符及其编码，使查找速度最快？（2）设计一个函数check(code[],L)，判断给定的字符编码是否具有前缀特性。（3）说明(2)中时间复杂度。","a":"（1）使用字典树(Trie/前缀树)存储编码。每个结点有两个分支(0和1)，叶结点标记对应字符。查找编码时沿0/1路径走到叶结点，查找时间O(编码长度)。（2）构建Trie时，若插入过程中遇到已有标记的结点(其他编码到此结束)，说明当前编码是某编码的前缀；若插入结束时当前结点已有孩子，说明某编码是当前编码的前缀。前缀特性检查O(总编码位数)。（3）时间复杂度O(n*L)，n为字符个数，L为最长编码长度。","ch":103,"s":10})
qs.append({"y":2020,"c":"某计算机字长16位，主存按字节编址。指令格式：OP(4位)Rd(4位)Rs(4位)Rt(4位)。转移指令采用相对寻址方式，偏移量用补码表示，寻址单位为指令字(每条指令16位)。（1）该指令系统最多可有多少条指令？最多可有多少个通用寄存器？（2）若PC的内容为2000H，转移指令的偏移量字段为06H，则转移的目标地址是什么？（3）若偏移量字段为FCH，则转移的目标地址是什么？","a":"（1）OP占4位，最多16条指令。Rd/Rs/Rt各占4位，最多16个通用寄存器。（2）偏移量06H=6，目标地址=PC+6*2(指令字2字节)=2000H+0CH=200CH。取指后PC=2002H，转移地址=2002H+0CH=200EH(取决于是否取指后PC已更新)。（3）FCH补码=-4，目标地址=2002H+(-4)*2=2002H-8=1FFAH。","ch":204,"s":20})
qs.append({"y":2020,"c":"某32位计算机按字节编址，虚拟地址为32位，物理地址为24位，页大小为4KB，TLB采用全相联映射，Cache共有64行，每行64B，采用直接映射。（1）TLB中用几位表示虚页号？用几位表示页框号？（2）Cache中物理地址划分为哪几个字段？各占几位？（3）某进程中有一个int型数组a[100][100]，每个元素占4B。进程的页表起始地址为00200000H，TLB初始为空。问：依次访问a[0][0]、a[0][1]、a[1][0]、a[1][1]、a[2][0]时，TLB缺失共发生多少次？","a":"（1）虚拟地址32位，页内偏移12位，虚页号=32-12=20位。物理地址24位，页内偏移12位，页框号=24-12=12位。（2）Cache 64行=2^6到行号6位，块大小64B到块内偏移6位。标记=24-6-6=12位。物理地址：[标记12位|行号6位|块内偏移6位]。（3）数组a[100][100]每行100*4B=400B。每页4KB可容约10行。访问a[0][0]虚页号x，TLB缺失1次填TLB。a[0][1]、a[1][0]、a[1][1]同页命中。a[2][0]可能同页(第2行在页码中800B<4096B)。仅a[0][0]时TLB缺失1次。","ch":303,"s":30})
qs.append({"y":2020,"c":"某系统有n个进程共享一个临界资源，系统使用PV操作实现进程互斥。（1）定义所需信号量及其初值。（2）写出各进程访问临界资源的通用代码。（3）若某个进程在临界区中执行时发生了中断，其他进程能否进入临界区？为什么？","a":"（1）信号量mutex=1(互斥信号量)。（2）P(mutex)；临界区；V(mutex)；（3）不能。因为临界区由mutex保护，只有执行V(mutex)后其他进程才能进入。若进程在临界区中断，mutex仍为0，其他进程在P(mutex)处阻塞。但如果中断处理程序修改了信号量或临界区，可能导致不一致。操作系统通常禁止在临界区内响应中断或设置中断屏蔽。","ch":302,"s":30})
qs.append({"y":2020,"c":"某文件系统采用FAT管理磁盘空间，FAT表项为16位。磁盘大小为1GB，盘块大小为2KB。（1）该文件系统最多可管理多少个盘块？（2）FAT需占用多少存储空间？（3）若某个文件占用的磁盘块号依次为：5,8,10,3,12。画出该文件对应的FAT表项。","a":"（1）1GB/2KB=2^30/2^11=2^19=524288个盘块>2^16=65536。16位FAT最多管理65536块*2KB=128MB<1GB，不匹配！需改为32位FAT或调整盘块大小。（2）16位FAT：65536*2B=128KB。（3）FAT表：FAT[5]=8，FAT[8]=10，FAT[10]=3，FAT[3]=12，FAT[12]=EOF(如-1或FFFF)。其他表项为0(空闲)。","ch":304,"s":30})
qs.append({"y":2020,"c":"某主机的网络配置信息如下：IP地址：192.168.1.20，子网掩码：255.255.255.0，默认网关：192.168.1.1，DNS服务器：8.8.8.8。（1）该主机所在网络的网络地址和广播地址分别是什么？（2）该主机最多可以和该网络中多少台其他主机直接通信？（3）若该主机要访问域名为www.example.com的Web服务器，请描述域名解析过程。","a":"（1）网络地址=192.168.1.0，广播地址=192.168.1.255。（2）可用IP数=256-2(网络地址和广播地址)=254台主机，可与其他253台主机直接通信。（3）主机向DNS服务器8.8.8.8发送DNS查询请求解析www.example.com；DNS服务器递归或迭代查询根域名服务器到.com顶级域名服务器到example.com权威域名服务器，获取IP地址后返回给主机。主机用该IP地址访问Web服务器。","ch":404,"s":40})

# 2021
qs.append({"y":2021,"c":"已知某排序算法如下：void sort(int A[],int n){for(int i=1;i<n;i++){int key=A[i];int low=0,high=i-1;while(low<=high){int mid=(low+high)/2;if(A[mid]>key)high=mid-1;else low=mid+1;}for(int j=i-1;j>=low;j--)A[j+1]=A[j];A[low]=key;}}（1）该算法属于何种排序算法？（2）该算法是否稳定？说明理由。（3）分析该算法的最好时间复杂度和最坏时间复杂度。","a":"（1）折半插入排序(Binary Insertion Sort)，用二分查找确定插入位置，再移动元素。（2）稳定。当A[mid]==key时选择mid右侧位置(low=mid+1)，保证相等元素的相对顺序不变。（3）最好(已有序)：每轮1次比较(立即退出)，移动0次到O(n)。最坏(逆序)：每轮log i次比较，i-1次移动到O(n^2)。平均O(n^2)。虽然比较次数O(nlogn)，移动次数仍为O(n^2)。","ch":106,"s":10})
qs.append({"y":2021,"c":"对给定的图G进行广度优先搜索(BFS)遍历，得到的遍历序列为a,b,c,d,e,f,g。（1）BFS遍历过程中使用了哪种辅助数据结构？其作用是什么？（2）画出图G的一种可能的邻接表存储结构。（3）写出BFS算法的伪代码。","a":"（1）使用队列作为辅助数据结构。作用：存储待访问的邻接顶点，保证先访问的顶点的邻接点先被访问(FIFO)。（2）略(根据BFS序列推断图结构)。（3）BFS(G,v):visited[v]=true;queue.push(v);while(!queue.empty()){u=queue.pop();for each w in Adj[u]:if!visited[w]{visited[w]=true;queue.push(w);}}","ch":104,"s":10})
qs.append({"y":2021,"c":"某32位计算机中，CPU主频为2.5GHz。某C语言程序中有如下循环：int a[8][32];for(int i=0;i<8;i++)for(int j=0;j<32;j++)a[i][j]=i*32+j;数组a按行优先方式存储，每个int占4字节。假定：指令Cache和数据Cache分离，数据Cache采用直接映射方式，容量为128B，每行8B。Cache初始为空。数组a首地址为08000000H。（1）主存地址中标记、行号和块内地址字段各占多少位？（2）数组a总共占用了多少数据Cache行？（3）执行该循环时数据Cache的命中率是多少？","a":"（1）主存地址32位。块大小8B=2^3B，块内偏移3位。Cache 128B/8B=16行，行号4位。标记=32-4-3=25位。（2）数组大小=8*32*4B=1024B=128个Cache行。但Cache只有16行，直接映射冲突严重。（3）每行2个int(8B/4B=2)。访问第1个int不命中(加载该行)，第2个命中。命中率=50%。","ch":203,"s":20})
qs.append({"y":2021,"c":"某系统采用请求分页存储管理，进程P有4个页面，系统为P分配了3个页框。进程P的页面访问序列为：4,3,2,1,4,3,5,4,3,2,1,5。（1）采用FIFO页面置换算法，计算缺页中断次数和缺页率。（2）采用LRU页面置换算法，计算缺页中断次数和缺页率。（3）对比分析两种算法的性能差异。","a":"（1）FIFO：4缺页到3缺页到2缺页到1缺页(1,3,2换4)到4缺页(1,4,2换3)到3缺页(1,4,3换2)到5缺页(5,4,3换1)到4命中到3命中到2缺页(5,2,3换4)到1缺页(5,2,1换3)到5命中。缺页9次，缺页率=9/12=75%。（2）LRU：4缺页到3缺页到2缺页到1缺页(1,3,2换4)到4缺页(1,4,2换3)到3缺页(1,4,3换2)到5缺页(5,4,3换1)到4命中到3命中到2缺页(2,4,3换5)到1缺页(2,1,3换4)到5缺页(2,1,5换3)。缺页10次，缺页率=83.3%。（3）通常LRU优于FIFO，但在某些特殊访问模式下可能相反(Belady异常)。此例FIFO 9次，LRU 10次。","ch":303,"s":30})
qs.append({"y":2021,"c":"某系统有4个进程P1、P2、P3、P4，其运行时间分别为1,2,3,4(单位：s)，优先级从高到低依次为P1、P2、P3、P4。（1）若采用先来先服务(FCFS)调度算法，计算平均等待时间和平均周转时间(设到达顺序为P1到P4)。（2）若采用非抢占式优先级调度算法，计算平均等待时间和平均周转时间。（3）若采用时间片轮转(RR)调度算法，时间片为1s，到达顺序为P1到P2到P3到P4，计算平均等待时间和平均周转时间。","a":"（1）FCFS(同时到达)：P1运行0-1等待0周转1；P2运行1-3等待1周转3；P3运行3-6等待3周转6；P4运行6-10等待6周转10。平均等待=(0+1+3+6)/4=2.5s，平均周转=(1+3+6+10)/4=5s。（2）非抢占优先级(P1最高到P4最低)：P1(0-1)、P2(1-3)、P3(3-6)、P4(6-10)。结果同FCFS。（3）RR时间片1s：P1(0-1)、P2(1-2)、P3(2-3)、P4(3-4)、P2(4-5完成)、P3(5-6)到P3还需1s(6-7完成)、P4(7-8)到P4还需2s(8-10完成)。等待：P1=0，P2=(1-0)+(4-2)=3实际=5-1-2=2，P3=7-3-3=1，P4=10-4-4=2。平均等待=(0+2+1+2)/4=1.25s，平均周转=(1+5+7+10)/4=5.75s。","ch":301,"s":30})
qs.append({"y":2021,"c":"某磁盘的转速为10000转/分，平均寻道时间为6ms。每个磁道有500个扇区，每个扇区512B。（1）该磁盘的平均存取时间是多少？（2）若采用SCAN(电梯)磁盘调度算法，磁头当前在50号磁道，向磁道号增加的方向移动。请求序列为：100,180,40,120,10,160。给出服务顺序和平均寻道长度。","a":"（1）平均旋转延迟=半圈时间=60/10000/2=3ms。平均存取时间=平均寻道6ms+平均旋转延迟3ms+传输时间(忽略)=9ms。（2）SCAN算法：当前50号向增大方向。服务顺序：100到120到160到180到40到10(到达最远端180后反向)。寻道长度：|100-50|=50，|120-100|=20，|160-120|=40，|180-160|=20，|40-180|=140，|10-40|=30。总寻道=300，平均=300/6=50。","ch":305,"s":30})
qs.append({"y":2021,"c":"某UDP用户数据报的数据部分为8192字节，在数据链路层使用以太网传送。（1）该UDP数据报需要分成几个IP分片？每个分片的片偏移字段的值是多少？（2）若第一个分片在传输中丢失，接收方能否正确组装UDP数据报？（3）为什么DNS使用UDP而不是TCP？","a":"（1）以太网MTU=1500B，IP头20B到数据载荷1480B。UDP头8B+数据8192B=8200B。分片以8B为单位。第1片：偏移0数据1480B；第2片：偏移185数据1480B；第3片：偏移370数据1480B；第4片：偏移555数据1480B；第5片：偏移740数据1480B；第6片：偏移925数据792B。共6片。（2）不能。IP分片中任一片丢失，接收方无法完整组装原始IP数据报，整个数据报将被丢弃(超时后)。（3）DNS查询响应数据量小(通常<512B)，UDP无需建立连接开销小、延迟低。TCP需三次握手和四次挥手，开销大。对于简单查询，UDP更高效。","ch":404,"s":40})

